import os, sys
from subprocess import Popen, PIPE


def convertDocument(inputfile, outputfile, format):
    """
    Convert a document from one format to another using LibreOffice headless mode.

    Parameters:
        inputfile (str) - The input file name.
        outputfile (str) - The output file name.
        format (str) - The format of the output file.

    Returns:
        bool - True if successful, False otherwise
    """
    # Check that the format is supported by LibreOffice
    supportedFormats = ['pdf', 'docx']
    if not format in supportedFormats:
        print('Unsupported format')
        return False

    # Create a subprocess to call LibreOffice
    try:
        p = Popen(['soffice', '--headless', '--convert-to', format, inputfile], stdout=PIPE)
    except Exception as e:
        print(e)
        return False

    # Wait for the subprocess to finish and check that it was successful
    try:
        p.wait()
        if not os.path.isfile(outputfile):
            raise Exception('File not found')

        return True
    except Exception as e:
        print(e)
        return False